#include <iostream>

void printArrayElements(int* arr, int size);

int main() {
    std::cout << "Printing myArr: ";
    int myArr[] = {10, 20, 30, 40, 50};
    int arrSize = sizeof(myArr) / sizeof(myArr[0]);
    printArrayElements(myArr, arrSize);

    std::cout << "Printing emptyArr: ";
    int emptyArr[] = {};
    int emptyArrSize = 0;
    printArrayElements(emptyArr, emptyArrSize);

    std::cout << "Printing nullArr: ";
    int* nullArr = nullptr;
    int nullArrSize = 5;
    printArrayElements(nullArr, nullArrSize);

    std::cout << "Printing anotherArr with negative size: ";
    int anotherArr[] = {1, 2, 3};
    int negativeSize = -2;
    printArrayElements(anotherArr, negativeSize);

    std::cout << "Printing singleElementArr: ";
    int singleElementArr[] = {100};
    int singleElementArrSize = 1;
    printArrayElements(singleElementArr, singleElementArrSize);

    return 0;
}
